const input = $input.first().json;
const summary = input.summary || [];
const failedMetrics = summary.filter((entry) => entry.status === 'failed');
const failedMetricKeys = [...new Set(failedMetrics.map((entry) => entry.metricKey).filter(Boolean))];
const enableRetryWorkflow = String(input.ENABLE_RETRY_WORKFLOW ?? 'true').toLowerCase() !== 'false';
const maxRetries = Math.max(1, Number(input.MAX_RETRIES || 3));
return [{
  json: {
    summary,
    failedMetrics,
    failedMetricKeys,
    '✅START_DATE': input['✅START_DATE'],
    '✅END_DATE': input['✅END_DATE'],
    '✅SPREADSHEET_URL_OR_ID': input['✅SPREADSHEET_URL_OR_ID'],
    '✅SPREADSHEET_ID': input['✅SPREADSHEET_ID'],
    '✅SHEET_NAME': input['✅SHEET_NAME'],
    '✅RANGE': input['✅RANGE'],
    '✅COLUMNS': input['✅COLUMNS'],
    '✅AMAZON_MARKETPLACE_ID': input['✅AMAZON_MARKETPLACE_ID'],
    '✅AMAZON_ADS_CLIENT_ID': input['✅AMAZON_ADS_CLIENT_ID'],
    '✅AMAZON_ADS_CLIENT_SECRET': input['✅AMAZON_ADS_CLIENT_SECRET'],
    '✅AMAZON_ADS_REFRESH_TOKEN': input['✅AMAZON_ADS_REFRESH_TOKEN'],
    '✅AMAZON_ADS_PROFILE_ID': input['✅AMAZON_ADS_PROFILE_ID'],
    '✅AMAZON_SP_CLIENT_ID': input['✅AMAZON_SP_CLIENT_ID'],
    '✅AMAZON_SP_CLIENT_SECRET: ': input['✅AMAZON_SP_CLIENT_SECRET: '],
    '✅AMAZON_SP_REFRESH_TOKEN': input['✅AMAZON_SP_REFRESH_TOKEN'],
    '✅GOOGLE_SERVICE_ACCOUNT_EMAIL': input['✅GOOGLE_SERVICE_ACCOUNT_EMAIL'],
    '✅GOOGLE_PRIVATE_KEY': input['✅GOOGLE_PRIVATE_KEY'],
    '✅GOOGLE_SCOPE': input['✅GOOGLE_SCOPE'],
    INCLUDE_LIST: input.INCLUDE_LIST || '',
    MAX_RETRIES: String(maxRetries),
    ENABLE_RETRY_WORKFLOW: enableRetryWorkflow ? 'true' : 'false',
    shouldAutoRetry: enableRetryWorkflow && failedMetricKeys.length > 0,
    orchestratorRunId: $execution.id,
  },
}];

const seed = $('Set Credentials').first().json;
const input = $input.first().json;
const issuedAt = new Date().toISOString();

const refreshBufferSeconds = Number(seed.AUTH_REFRESH_BUFFER_SECONDS || input.AUTH_REFRESH_BUFFER_SECONDS || 300);

const amazonAdsNode = $('Mint Amazon Access Token').first().json;
const googleNode = $('Mint Google Access Token').first().json;
const spNode = $('Mint SP Access Token').first().json;

const amazonExpiresIn = Number(amazonAdsNode.expires_in || 3600);
const googleExpiresIn = Number(googleNode.expires_in || 3600);
const spExpiresIn = Number(spNode.expires_in || 3600);

return [{
  json: {
    ...seed,
    ...input,
    auth: {
      amazon: {
        accessToken: amazonAdsNode.access_token,
        clientId: seed['✅AMAZON_ADS_CLIENT_ID'],
        profileId: seed['✅AMAZON_ADS_PROFILE_ID'],
        issuedAt,
        expiresAt: new Date(Date.now() + amazonExpiresIn * 1000).toISOString(),
        spAccessToken: spNode.access_token,
        spIssuedAt: issuedAt,
        spExpiresAt: new Date(Date.now() + spExpiresIn * 1000).toISOString(),
      },
      google: {
        accessToken: googleNode.access_token,
        scope: seed['✅GOOGLE_SCOPE'] || 'https://www.googleapis.com/auth/spreadsheets',
        issuedAt: seed.googleIssuedAt || input.googleIssuedAt || issuedAt,
        expiresAt: seed.googleExpiresAt || input.googleExpiresAt || new Date(Date.now() + googleExpiresIn * 1000).toISOString(),
      },
      meta: {
        refreshBufferSeconds,
      },
    },
  },
}];

const crypto = require('crypto');

function b64url(value) {
  return Buffer.from(value)
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function getCredentialsFromN8n() {
  try {
    return $('Set Credentials').first().json || {};
  } catch {
    return $input.first().json || {};
  }
}

function normalizePrivateKey(raw) {
  let value = String(raw || '').trim();

  if (!value) {
    return '';
  }

  if (
    (value.startsWith('"') && value.endsWith('"')) ||
    (value.startsWith("'") && value.endsWith("'"))
  ) {
    value = value.slice(1, -1);
  }

  value = value
    .replace(/\\r\\n/g, '\n')
    .replace(/\\n/g, '\n')
    .replace(/\r\n/g, '\n')
    .trim();

  if (!value.includes('BEGIN')) {
    value = [
      'REDACTED',
    ].join('\n');
  }

  return value;
}

function createPrivateKeyOrThrow(privateKeyPem) {
  try {
    return crypto.createPrivateKey({
      key: privateKeyPem,
      format: 'pem',
    });
  } catch (error) {
    const firstLine = privateKeyPem.split('\n')[0] || '<empty>';
    throw new Error(
      `Invalid GOOGLE_PRIVATE_KEY format. First line: ${firstLine}. Original error: ${error.message}`
    );
  }
}

const input = $input.first().json || {};
const credentials = { ...getCredentialsFromN8n(), ...input };

const serviceAccountEmail = String(credentials['✅GOOGLE_SERVICE_ACCOUNT_EMAIL'] || '').trim();
const privateKeyPem = normalizePrivateKey(credentials['✅GOOGLE_PRIVATE_KEY']);
const scope = String(
  credentials['✅GOOGLE_SCOPE'] || 'https://www.googleapis.com/auth/spreadsheets.readonly'
).trim();

if (!serviceAccountEmail || !privateKeyPem) {
  throw new Error('Missing GOOGLE_SERVICE_ACCOUNT_EMAIL or GOOGLE_PRIVATE_KEY');
}

const privateKey = createPrivateKeyOrThrow(privateKeyPem);
const now = Math.floor(Date.now() / 1000);

const encodedHeader = b64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const encodedPayload = b64url(
  JSON.stringify({
    iss: serviceAccountEmail,
    scope,
    aud: 'https://oauth2.googleapis.com/token',
    iat: now,
    exp: now + 3600,
  })
);

const signingInput = `${encodedHeader}.${encodedPayload}`;
const signature = crypto
  .sign('RSA-SHA256', Buffer.from(signingInput, 'utf8'), privateKey)
  .toString('base64')
  .replace(/=/g, '')
  .replace(/\+/g, '-')
  .replace(/\//g, '_');

return [
  {
    json: {
      ...input,
      assertion: `${signingInput}.${signature}`,
    },
  },
];
